8907 SelectPatternResult llvm::matchDecomposedSelectPattern(
8908     CmpInst *CmpI, Value *TrueVal, Value *FalseVal, Value *&LHS, Value *&RHS,
8909     FastMathFlags FMF, Instruction::CastOps *CastOp, unsigned Depth) {
8910   CmpInst::Predicate Pred = CmpI->getPredicate();
8911   Value *CmpLHS = CmpI->getOperand(0);
8912   Value *CmpRHS = CmpI->getOperand(1);
8913   if (isa<FPMathOperator>(CmpI) && CmpI->hasNoNaNs())
8914     FMF.setNoNaNs();
8915 
8916   // Bail out early.
8917   if (CmpI->isEquality())
8918     return {SPF_UNKNOWN, SPNB_NA, false};
8919 
8920   // Deal with type mismatches.
8921   if (CastOp && CmpLHS->getType() != TrueVal->getType()) {
8922     if (Value *C = lookThroughCast(CmpI, TrueVal, FalseVal, CastOp)) {
8923       // If this is a potential fmin/fmax with a cast to integer, then ignore
8924       // -0.0 because there is no corresponding integer value.
8925       if (*CastOp == Instruction::FPToSI || *CastOp == Instruction::FPToUI)
8926         FMF.setNoSignedZeros();
8927       return ::matchSelectPattern(Pred, FMF, CmpLHS, CmpRHS,
8928                                   cast<CastInst>(TrueVal)->getOperand(0), C,
8929                                   LHS, RHS, Depth);
8930     }
8931     if (Value *C = lookThroughCast(CmpI, FalseVal, TrueVal, CastOp)) {
8932       // If this is a potential fmin/fmax with a cast to integer, then ignore
8933       // -0.0 because there is no corresponding integer value.
8934       if (*CastOp == Instruction::FPToSI || *CastOp == Instruction::FPToUI)
8935         FMF.setNoSignedZeros();
8936       return ::matchSelectPattern(Pred, FMF, CmpLHS, CmpRHS,
8937                                   C, cast<CastInst>(FalseVal)->getOperand(0),
8938                                   LHS, RHS, Depth);
8939     }
8940   }
8941   return ::matchSelectPattern(Pred, FMF, CmpLHS, CmpRHS, TrueVal, FalseVal,
8942                               LHS, RHS, Depth);
