9047 bool llvm::matchSimpleRecurrence(const PHINode *P, BinaryOperator *&BO,
9048                                  Value *&Start, Value *&Step) {
9049   // Handle the case of a simple two-predecessor recurrence PHI.
9050   // There's a lot more that could theoretically be done here, but
9051   // this is sufficient to catch some interesting cases.
9052   if (P->getNumIncomingValues() != 2)
9053     return false;
9054 
9055   for (unsigned i = 0; i != 2; ++i) {
9056     Value *L = P->getIncomingValue(i);
9057     Value *R = P->getIncomingValue(!i);
9058     auto *LU = dyn_cast<BinaryOperator>(L);
9059     if (!LU)
9060       continue;
9061     unsigned Opcode = LU->getOpcode();
9062 
9063     switch (Opcode) {
9064     default:
9065       continue;
9066     // TODO: Expand list -- xor, gep, uadd.sat etc.
9067     case Instruction::LShr:
9068     case Instruction::AShr:
9069     case Instruction::Shl:
9070     case Instruction::Add:
9071     case Instruction::Sub:
9072     case Instruction::UDiv:
9073     case Instruction::URem:
9074     case Instruction::And:
9075     case Instruction::Or:
9076     case Instruction::Mul:
9077     case Instruction::FMul: {
9078       Value *LL = LU->getOperand(0);
9079       Value *LR = LU->getOperand(1);
9080       // Find a recurrence.
9081       if (LL == P)
9082         L = LR;
9083       else if (LR == P)
9084         L = LL;
9085       else
9086         continue; // Check for recurrence with L and R flipped.
9087 
9088       break; // Match!
9089     }
9090     };
9091 
9092     // We have matched a recurrence of the form:
9093     //   %iv = [R, %entry], [%iv.next, %backedge]
9094     //   %iv.next = binop %iv, L
9095     // OR
9096     //   %iv = [R, %entry], [%iv.next, %backedge]
9097     //   %iv.next = binop L, %iv
9098     BO = LU;
9099     Start = R;
9100     Step = L;
9101     return true;
9102   }
9103   return false;
9104 }
