8750 static Value *lookThroughCastConst(CmpInst *CmpI, Type *SrcTy, Constant *C,
8751                                    Instruction::CastOps *CastOp) {
8752   const DataLayout &DL = CmpI->getDataLayout();
8753 
8754   Constant *CastedTo = nullptr;
8755   switch (*CastOp) {
8756   case Instruction::ZExt:
8757     if (CmpI->isUnsigned())
8758       CastedTo = ConstantExpr::getTrunc(C, SrcTy);
8759     break;
8760   case Instruction::SExt:
8761     if (CmpI->isSigned())
8762       CastedTo = ConstantExpr::getTrunc(C, SrcTy, true);
8763     break;
8764   case Instruction::Trunc:
8765     Constant *CmpConst;
8766     if (match(CmpI->getOperand(1), m_Constant(CmpConst)) &&
8767         CmpConst->getType() == SrcTy) {
8768       // Here we have the following case:
8769       //
8770       //   %cond = cmp iN %x, CmpConst
8771       //   %tr = trunc iN %x to iK
8772       //   %narrowsel = select i1 %cond, iK %t, iK C
8773       //
8774       // We can always move trunc after select operation:
8775       //
8776       //   %cond = cmp iN %x, CmpConst
8777       //   %widesel = select i1 %cond, iN %x, iN CmpConst
8778       //   %tr = trunc iN %widesel to iK
8779       //
8780       // Note that C could be extended in any way because we don't care about
8781       // upper bits after truncation. It can't be abs pattern, because it would
8782       // look like:
8783       //
8784       //   select i1 %cond, x, -x.
8785       //
8786       // So only min/max pattern could be matched. Such match requires widened C
8787       // == CmpConst. That is why set widened C = CmpConst, condition trunc
8788       // CmpConst == C is checked below.
8789       CastedTo = CmpConst;
8790     } else {
8791       unsigned ExtOp = CmpI->isSigned() ? Instruction::SExt : Instruction::ZExt;
8792       CastedTo = ConstantFoldCastOperand(ExtOp, C, SrcTy, DL);
8793     }
8794     break;
8795   case Instruction::FPTrunc:
8796     CastedTo = ConstantFoldCastOperand(Instruction::FPExt, C, SrcTy, DL);
8797     break;
8798   case Instruction::FPExt:
8799     CastedTo = ConstantFoldCastOperand(Instruction::FPTrunc, C, SrcTy, DL);
8800     break;
8801   case Instruction::FPToUI:
8802     CastedTo = ConstantFoldCastOperand(Instruction::UIToFP, C, SrcTy, DL);
8803     break;
8804   case Instruction::FPToSI:
8805     CastedTo = ConstantFoldCastOperand(Instruction::SIToFP, C, SrcTy, DL);
8806     break;
8807   case Instruction::UIToFP:
8808     CastedTo = ConstantFoldCastOperand(Instruction::FPToUI, C, SrcTy, DL);
